import math
def build(arr): n=len(arr); log=[0]*(n+1); for i in range(2,n+1): log[i]=log[i//2]+1; K=log[n]+1; st=[[0]*n for _ in range(K)]; for i in range(n): st[0][i]=arr[i]; for k in range(1,K): for i in range(n-(1<<k)+1): st[k][i]=min(st[k-1][i], st[k-1][i+(1<<(k-1))]); return st,log
def query(st,log,l,r): j=log[r-l+1]; return min(st[j][l], st[j][r-(1<<j)+1])

import heapq
from collections import Counter
def solve(s): count=Counter(s); max_heap=[(-c,ch) for ch,c in count.items()]; heapq.heapify(max_heap); res=[]; prev=None; while max_heap: c,ch=heapq.heappop(max_heap); res.append(ch); if prev: heapq.heappush(max_heap,prev); prev=(c+1,ch) if c+1<0 else None; if prev: return ''; return ''.join(res)
